public static ETGShippingAdviseDP construct()
{
    ETGShippingAdviseDP  dataProvider;

    dataProvider = new ETGShippingAdviseDP();

    return dataProvider;
}

public ETGShippingAdviseTmp processReport (ETGShippingAdviseContract _contract)
{
    SalesAgreementId            salesAgreementId;
    SalesAgreementHeader        salesAgreementHeader;

    salesAgreementId        =   _contract.parmSalesAgreementId();
    salesAgreementHeader    =   SalesAgreementHeader::findAgreementId(salesAgreementId);

    shippingAdviseHeaderTmp.SalesAgreementId            =   salesAgreementHeader.SalesNumberSequence;
    shippingAdviseHeaderTmp.CustAccount                 =   salesAgreementHeader.CustAccount;
    shippingAdviseHeaderTmp.SalesAgreementHeaderRecId   =   salesAgreementHeader.RecId;

    ttsbegin;
    shippingAdviseHeaderTmp.insert();
    ttscommit;

    // Select all rows from tmp table and return
    select shippingAdviseHeaderTmp;
    return shippingAdviseHeaderTmp;
}
